import{_ as o,o as t,c as a,a3 as n}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"38A. Personal Leave","description":"","frontmatter":{"title":"38A. Personal Leave","eba":"Mental Health Services 2024-2028","topics":["leave","personal-leave","preliminary"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/leave/38A-personal-leave.md","filePath":"ebas/mental-health/common-terms/leave/38A-personal-leave.md"}'),r={name:"ebas/mental-health/common-terms/leave/38A-personal-leave.md"};function s(i,e,l,p,c,h){return t(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="_38a-personal-leave" tabindex="-1">38A. Personal Leave <a class="header-anchor" href="#_38a-personal-leave" aria-label="Permalink to &quot;38A. Personal Leave&quot;">​</a></h1><p>Note: This clause does not apply to casual Employees. The entitlements of casual Employees are set out in <a href="/eba/ebas/mental-health/common-terms/leave/38C-caring-responsibilities-casual-employees.html">clause 38C</a> (Casual Employment – Caring Responsibility). 38A.1. Amount of Paid Personal Leave</p><p><strong>(a)</strong> A full time Employee is entitled to the following amount of paid personal leave:</p><p><strong>(i)</strong> 91 hours and 12 minutes or as provided by the NES (whichever is the greater) in the first year of service</p><p><strong>(ii)</strong> 106 hours and 24 minutes or as provided by the NES (whichever is the greater) in each year in the second, third and fourth years of service</p><p><strong>(iii)</strong> 159 hours and 36 minutes in the fifth and following years of service.</p><p><strong>(b)</strong> A part time Employee accrues leave on a pro rata basis.</p><p><strong>(c)</strong> Paid personal leave accrues progressively during a year of service according to the Employee’s ordinary hours of work (excluding overtime) and accumulates from year to year. 38A.2. Additional Paid Personal Leave</p><p><strong>(a)</strong> In addition 38A.1, and <a href="/eba/ebas/mental-health/common-terms/leave/44-compassionate-leave.html">clause 44</a> (Compassionate Leave) a full time Employee is entitled to an additional 30 hours and 24 minutes of paid personal leave each year where their paid personal leave entitlement has been exhausted.</p><p><strong>(b)</strong> A part time Employee accrues leave on a pro rata basis.</p><p><strong>(c)</strong> This additional leave does not accrue from year to year. 38A.3. Access to paid personal leave Subject to the conditions set out in this clause, an Employee may take paid personal leave if the leave is taken:</p><p><strong>(a)</strong> due to personal illness or injury (sick leave); or</p><p><strong>(b)</strong> to care for or support a member of the Employee’s Immediate Family or household, or to care for someone who is wholly or substantially dependant on the Employee (carer&#39;s leave), because of:</p><p><strong>(i)</strong> a personal illness or injury affecting them including due to the loss of pregnancy (without derogation of any other entitlements under this Agreement); or</p><p><strong>(ii)</strong> an unexpected emergency; or</p><p><strong>(iii)</strong> the requirement to provide ongoing care or attention to another person who is wholly or substantially dependent on the Employee, provided that the care or attention is not wholly or substantially on a commercial basis (carer’s leave).</p><p><strong>(c)</strong> In normal circumstances an Employee must not take personal leave under this clause to care for someone where another person has taken leave to care for the same person.</p><p><strong>(d)</strong> Personal Leave to Attend Appointments Notwithstanding subclause 38A.3(a), an Employee may use up to five days personal leave, in aggregate, in any year of service on account of a disability or where the Employee is required to attend a registered health practitioner or diagnostic appointment. 38A.4. Evidence requirements – Sick Leave</p><p><strong>(a)</strong> An Employee taking sick leave will give the Employer evidence that would satisfy a reasonable person the Employee is absent due to personal illness or injury or, in the case of leave taken to attend an appointment (see subclause 38A.3(d)) evidence of attendance.</p><p><strong>(b)</strong> Exception to evidence requirement-single day absences</p><p><strong>(i)</strong> An Employee may be absent for a single day without evidence of personal illness or injury as required at clause 38A.4(a) above, on not more than five occasions per year of service. However, an Employee will not be entitled to this benefit if the Employee fails to notify the Employer pursuant to the health service procedure set out at subclause 38A.5(a) below.</p><p><strong>(ii)</strong> An Employee classified under Part 2 of <a href="/eba/ebas/mental-health/schedules/07-management-and-administrative-officers-classifications.html">Schedule 7</a> of this Agreement may be absent through personal illness or injury on one day in addition to the entitlement at 38A.4(b)(i) in any one year of service without having to provide evidence to the Employer. 38A.5. Notice requirements</p><p><strong>(a)</strong> An Employee should inform the Employer of their absence no less than 1.5 hours prior to the commencement of the rostered shift or as soon as reasonably practicable to allow the Employer to take necessary steps to backfill the absence. This provision does not apply where an Employee could not comply because of circumstances beyond the Employee&#39;s control.</p><p><strong>(b)</strong> The Employer will inform Employees of the procedure for notification by Employees of their inability to attend work due to illness or injury, such notifications will be registered, detailing the time of notification and the name of the Employee.</p><p><strong>(c)</strong> Failure to provide notice of absence Personal leave will not be withheld by an Employer until all reasonable steps have been taken to investigate the Employee&#39;s lack of notification as required by clause 38A.5. (a) regarding the absence from duty. Such an investigation must provide the Employee with an opportunity to give reasons as to why notification was not given. 38A.6. Evidence Requirements - Carers Leave</p><p><strong>(a)</strong> Evidence requirements The Employee must, if required by the Employer, establish by production of a Proof of Attendance or statutory declaration or other evidence that would satisfy a reasonable person, that a member of the Employee&#39;s immediate family or household has either:</p><p><strong>(i)</strong> an illness or injury; or</p><p><strong>(ii)</strong> an unexpected emergency that requires their care or support. In the case of an unexpected emergency, the Employee will identify the nature of the emergency. An &#39;unexpected emergency&#39;</p><p>includes providing care or support to a member of the Employee’s immediate family or household experiencing family and domestic violence as described at <a href="/eba/ebas/mental-health/common-terms/leave/45-family-and-domestic-violence-leave.html">clause 45</a>(Family and Domestic Violence).</p><p><strong>(b)</strong> Notice requirements</p><p><strong>(i)</strong> The Employee must, where practicable, give the Employer notice of the intention to take leave prior to the absence, that includes: A. the name of the person requiring care or support and their relationship to the Employee, B. the reasons for taking such leave, and C. the estimated length of absence.</p><p><strong>(ii)</strong> If it is not practicable for the Employee to give prior notice of absence, the Employee must notify the Employer of the absence as soon as reasonably practicable.</p><p><strong>(iii)</strong> Notification of absence due to this clause shall be as per procedure at 38A.5(b).</p><p><strong>(c)</strong> Unpaid leave where paid personal leave accruals exhausted An Employee who has exhausted paid personal leave entitlements is entitled to take unpaid carer&#39;s leave. The Employee is entitled to take up to two days (or two full shifts where ordinary shifts exceed 8 hours) per occasion, provided the evidentiary requirements are met. The Employee may also take unpaid carer&#39;s leave in shorter or longer periods to which the Employee and Employer agree. 38A.7. Payment for leave</p><p><strong>(a)</strong> Payment will be made based on the number of ordinary hours the Employee would have worked on the day or days on which the leave was taken.</p><p><strong>(b)</strong> An Employee utilising personal leave may take leave for part of a single day. Leave will be deducted on a time for time basis from the Employee’s accrued personal leave. 38A.8. Personal leave on a public holiday If the period during which an Employee takes paid personal leave includes a day or part-day that is a public holiday in the place where the Employee is based for work purposes, the Employee is taken not to be on paid personal leave on that public holiday. 38A.9. Portability of Personal Leave</p><p><strong>(a)</strong> Entitlement Subject to 38A.9(b) and (c), the Employer will credit accrued untaken personal leave to an Employee who transfers to the Employer from:</p><p><strong>(i)</strong> An Institution (as defined in <a href="/eba/ebas/mental-health/common-terms/leave/47-long-service-leave.html">clause 47.2</a>(e)); or</p><p><strong>(ii)</strong> subject to 38A.9(d) below: <strong>(A)</strong> a Council in Victoria as defined in the Local Government Act 2020 (Vic); or <strong>(B)</strong> a public health service in another State or Territory.</p><p><strong>(b)</strong> Allowable Period Continuity of service will be deemed to be unbroken where the period of absence is equal to or less than an Employee’s Allowable Period of Absence (as defined at <a href="/eba/ebas/mental-health/common-terms/leave/47-long-service-leave.html">clause 47.2</a>(a)) between an engagement with one employer named in subclause 38A.9(a) and another. An absence in excess of the Allowable Period of Absence (defined at <a href="/eba/ebas/mental-health/common-terms/leave/47-long-service-leave.html">clause 47.2</a>(a)) will exclude the Employee from any benefit under 38A.9.</p><p><strong>(c)</strong> Exception to Allowable Period Where any Employee for the sole purpose of undertaking is, with the written approval of the Employer, absent without pay for up to but not exceeding 104 weeks, such absence will not be deemed to have broken continuity of service but will not be counted as service for the purpose of establishing entitlement to personal leave portability·</p><p><strong>(d)</strong> Additional transfer limitations For the purposes of subclause 38A.9(a)(ii), the portability of accrued untaken personal leave with a Council in Victoria, or a public health service in another State or Territory is subject to the following additional matters:</p><p><strong>(i)</strong> portability will only apply on the first occasion that the Employee commences employment with an Employer on or after 20 May 2025; and</p><p><strong>(ii)</strong> portability will only apply where the break between ceasing employment with the relevant Council or interstate public health service, and commencing employment with an Employer, is no more than the greater of two months or the Allowable Period of Absence.</p><p><strong>(iii)</strong> once interstate accrual of personal leave is recognised in accordance with this clause, portability of that leave accrual will continue to be applicable subject to clause 38A.9.</p><p><strong>(e)</strong> Evidence Requirements: The Employer may require an Employee to produce a written statement from their previous employer specifying the amount of accrued untaken personal leave standing to the credit of such Employee at the time of leaving that previous employment.</p><p><strong>(f)</strong> Additional Provision Where an Employee transfers to an (or another) Employer and remains engaged on casual bank/or as a casual Employee with their previous Employer, the new Employer will not exclude the Employee from any benefit under this sub-clause on the basis of the ongoing casual engagement.</p><p>38A.10. Termination of Employment while on Personal Leave No Employer will terminate the services of an Employee during the currency of any period of personal leave, with the object of avoiding obligations under this clause.</p><p>Plain language terms: sick leave, sick day, carer&#39;s leave, off sick, unwell.</p>',49)])])}const u=o(r,[["render",s]]);export{d as __pageData,u as default};
